        // Validate and sanitize the user input to prevent command injection attacks
        // This is a good practice to prevent security issues
        if (userInput != null && !userInput.isEmpty()) {
            // Only allow specific commands to be executed
            if (userInput.equals("allowedCommand")) {
                try {
                    // Use a whitelist to ensure only allowed commands are executed
                    Process process = Runtime.getRuntime().exec("allowedCommand");
                    PrintWriter out = response.getWriter();
                    out.println("Command executed successfully");
                } catch (Exception e) {
                    // Handle the exception
                }
            } else {
                // Handle invalid input
                PrintWriter out = response.getWriter();
                out.println("Invalid input");
            }
        } else {
            // Handle empty input
